#include <stdio.h>
int main() {
    int T, N, M;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int A[N], B[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &B[i]);
        }
        scanf("%d", &M);
        int l, r, x, y;
        int prefix[N];
        for (int i = 0; i < M; i++) {
            scanf("%d %d %d %d", &l, &r, &x, &y);
            for (int j = l; j <= r; j++) {
                A[j-1] += x + (j-l)*y;
            }
            for (int j = 0; j < N; j++) {
                prefix[j] = A[j];
            }
            for (int j = 0; j < N; j++) {
                if (prefix[j] >= B[j]) {
                    printf("0 ");
                } else {
                    int low = 0, high = M;
                    while (low < high) {
                        int mid = (low + high) / 2;
                        int sum = 0;
                        for (int k = 0; k <= mid; k++) {
                            sum += x + (j-l)*y;
                        }
                        if (sum + A[j] >= B[j]) {
                            high = mid;
                        } else {
                            low = mid + 1;
                        }
                    }
                    if (low == M) {
                        printf("-1 ");
                    } else {
                        printf("%d ", low + 1);
                    }
                }
            }
            printf("\n");
        }
    }
    return 0;
}

