            int N = sc.nextInt();
            int[] A = new int[N];
            int[] B = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                B[i] = sc.nextInt();
            }
            int M = sc.nextInt();
            int l, r, x, y;
            int[] prefix = new int[N];
            for (int i = 0; i < M; i++) {
                l = sc.nextInt();
                r = sc.nextInt();
                x = sc.nextInt();
                y = sc.nextInt();
                for (int j = l; j <= r; j++) {
                    A[j-1] += x + (j-l)*y;
                }
                for (int j = 0; j < N; j++) {
                    prefix[j] = A[j];
                }
                for (int j = 0; j < N; j++) {
                    if (prefix[j] >= B[j]) {
                        System.out.print("0 ");
                    } else {
                        int low = 0, high = M;
                        while (low < high) {
                            int mid = (low + high) / 2;
                            int sum = 0;
                            for (int k = 0; k <= mid; k++) {
                                sum += x + (j-l)*y;
                            }
                            if (sum + A[j] >= B[j]) {
                                high = mid;
                            } else {
                                low = mid + 1;
                            }
                        }
                        if (low == M) {
                            System.out.print("-1 ");
                        } else {
                            System.out.print(low + 1 + " ");
                        }
                    }
                }
                System.out.println();
            }
        }
    }
}

