    A = list(map(int, sys.stdin.readline().split()))
    B = list(map(int, sys.stdin.readline().split()))
    M = int(sys.stdin.readline())
    for _ in range(M):
        l, r, x, y = map(int, sys.stdin.readline().split())
        for j in range(l-1, r):
            A[j] += x + (j-l+1)*y
        prefix = A[:]
        for j in range(N):
            if prefix[j] >= B[j]:
                print(0, end=' ')
            else:
                low, high = 0, M
                while low < high:
                    mid = (low + high) // 2
                    sum = 0
                    for k in range(mid+1):
                        sum += x + (j-l+1)*y
                    if sum + A[j] >= B[j]:
                        high = mid
                    else:
                        low = mid + 1
                if low == M:
                    print(-1, end=' ')
                else:
