const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    const A = readline().split(' ').map(x => parseInt(x));
    const B = readline().split(' ').map(x => parseInt(x));
    const M = parseInt(readline());
    for (let j = 0; j < M; j++) {
        const [l, r, x, y] = readline().split(' ').map(x => parseInt(x));
        for (let k = l; k <= r; k++) {
            A[k-1] += x + (k-l)*y;
        }
        const prefix = A.slice();
        for (let k = 0; k < N; k++) {
            if (prefix[k] >= B[k]) {
                process.stdout.write('0 ');
            } else {
                let low = 0, high = M;
                while (low < high) {
                    let mid = Math.floor((low + high) / 2);
                    let sum = 0;
                    for (let m = 0; m <= mid; m++) {
                        sum += x + (k-l)*y;
                    }
                    if (sum + A[k] >= B[k]) {
                        high = mid;
                    } else {
                        low = mid + 1;
                    }
                }
                if (low === M) {
                    process.stdout.write('-1 ');
                } else {
                    process.stdout.write(low + 1 + ' ');
                }
            }
        }
        process.stdout.write('\n');
    }
}
